pair G = intwithsquare[0];
pair F = intwithsquare[1];
draw(F--G,dashed);
draw(C--E);
label("F",F,E);
label("G",G,W);
label("E", E, S);
draw(F--E);
label("$3$", (E+D)/2, S);
label("$x$", (F+D)/2, E);
label("$6-x$", (F+C)/2, E);
label("$6-x$", (F+E)/2, fontsize(8));
draw(rightanglemark(C,D,E,2));
[/asy]

