label("1",(7.5,0),S);
label("$A$",(10,0),SE);
label("$B$",(0,0),SW);
label("$C$",(5,8.7),N);
label("$D$",(3,4),S);
[/asy]

We begin by drawing a diagram:

[asy]
size(100);
pair A,B,C;
real x = sqrt(3);
C=(0,0); A=(10,0); B=(0,10*x);
draw(A--B--C--cycle);
draw(rightanglemark(B,C,A,30));
label("$A$",A,SE); label("$C$",C,SW); label("$B$",B,NW); label("10",(A+C)/2,S);

real r = 5*sqrt(3) - 5;
